import{_ as t,o as r,c as a,a2 as o}from"./chunks/framework.BWuWLRhz.js";const n="/images/your-family-past-present-and-future/small-tree-missing-parts-600x383.png",p="/images/your-family-past-present-and-future/tree-128-600x502.png",s="/images/your-family-past-present-and-future/tree-many-600x445.png",i="/images/your-family-past-present-and-future/Pop-graph1.png",l="/images/your-family-past-present-and-future/Pop-graph-w-pop1.png",g="/images/your-family-past-present-and-future/pedigree-collapse.png",u="/images/your-family-past-present-and-future/diamond.png",m="/images/your-family-past-present-and-future/3rd-cousins-600x251.png",h="/images/your-family-past-present-and-future/Country-chart1-600x382.png",c="/images/your-family-past-present-and-future/prince-chart1-600x456.png",f="/images/your-family-past-present-and-future/descendant-cone-600x502.png",d="/images/your-family-past-present-and-future/telia1.png",y="/images/your-family-past-present-and-future/telia-cone-600x480.png",w="/images/your-family-past-present-and-future/pinit_fg_en_rect_gray_20.png",F=JSON.parse('{"title":"Your Family: Past, Present, and Future","description":"","frontmatter":{"title":"Your Family: Past, Present, and Future","titleZh":"你的家庭:过去、现在与未来","date":"2014-01-28T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2014/01/your-family-past-present-and-future.html","slug":"your-family-past-present-and-future"},"headers":[],"relativePath":"posts/your-family-past-present-and-future.md","filePath":"posts/your-family-past-present-and-future.md","lastUpdated":1782886257000}'),_={name:"posts/your-family-past-present-and-future.md"};function b(k,e,P,v,q,x){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="你的家庭-过去、现在与未来-·-your-family-past-present-and-future" tabindex="-1">你的家庭:过去、现在与未来 · Your Family: Past, Present, and Future <a class="header-anchor" href="#你的家庭-过去、现在与未来-·-your-family-past-present-and-future" aria-label="Permalink to &quot;你的家庭:过去、现在与未来 · Your Family: Past, Present, and Future&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2014/01/your-family-past-present-and-future.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2014/01/your-family-past-present-and-future.html</a> · 2014-01-28</p></blockquote><p>我还有一位健在的祖辈——我父亲的母亲,89岁了。</p><p>奶奶 (Nana)。</p><p>最近我去看望了奶奶,做了那些一贯的事——大声地跟她讲我自己的事,通过把最小化的浏览器窗口还原来&quot;修好她坏掉的机器&quot;,被告诫&quot;提摩西开慢点、走左道&quot;,尽管要拐弯的路口还在半英里之外。但我也借这次探望做了一件我这辈子做得<em>远远</em>不够的事——问她关于我们家族的事。</p><p>我不认识你,但我几乎可以打包票:你没有向你的祖父母(或年长的父母)问过足够多关于他们人生、以及他们父母人生的问题。我们都太以自我为中心了,正因如此,我们忘了去关心自己深陷其中的这段人生所处的<em>语境</em>。想了解世界史和本国历史,我们可以用谷歌查任何东西,但我们自己的个人历史——那些我们本<em>该</em>非常了解的东西——只能通过发问才能获取。</p><p>这次探望期间,奶奶把自己称作&quot;最后的莫希干人&quot;,意思基本上就是:她这辈子朝夕相处的人全都死了——她的丈夫、兄弟姐妹、堂表兄妹、朋友们都走了。这除了是史上最令人沮丧的事实之外,也是一记刺耳的警钟——一座关于我家族过往的丰富、详尽的信息宝库只存在于唯一一个地方——一个89岁的大脑里——如果我再继续瞎晃悠,这些信息里的绝大部分将永远消失。</p><p>所以这次探望,我开始提问。</p><p>她被我问烦了。</p><p>但只过了几分钟,她就沉浸在讲故事里了,接下来的三个小时,我听得<em>全神贯注</em>。</p><p>我了解到许多以前从不知道的关于她童年的事。我知道她和我爷爷是在大萧条 (Great Depression) 中长大的,但我从来不真正了解那些难以置信的细节——比如她曾亲眼看见一位母亲和她的孩子被房东扔到人行道上,任由他们在那儿挨饿受冻,直到街区里每一位邻居——他们自己也穷困潦倒——都凑上一两枚硬币,那位母亲才能再租一个月的房间。</p><p>我了解了我四位曾祖父母(父系那边)的一大堆事——同样,我以前知道他们的基本信息,但正是这些细节头一次让他们成为了真实的人。他们中有三位是在纽约条件恶劣的孤儿院里长大的——第四位则是十几岁时从拉脱维亚 (Latvia) 抛下她所熟悉的一切,独自坐船横渡大西洋,到了纽约在血汗工厂里干活。</p><p>我甚至第一次听到了关于我奶奶的奶奶的故事。她也是从拉脱维亚过来的,不过是单独过来的,晚年和这家人一起生活——而且显然性格相当有戏。谢天谢地,她1941年就去世了,就在她本会得知她的四个儿子(不像他们的母亲和妹妹,这四个儿子留在了拉脱维亚,因为他们在那儿有一份兴旺的家族生意)全都死于大屠杀 (Holocaust) 的几个月前。</p><p>这些事我<em>一件都不知道</em>。我怎么<em>直到现在才知道</em>我曾祖母的四个兄弟死于大屠杀?现在我第一次把我的四位曾祖父母和高祖母作为真实的、复杂的、有着独特性格的人来认识,我简直不敢相信自己活到现在,竟然对他们几乎一无所知也心安理得。特别是,正是他们经历过的孤儿院/血汗工厂/大萧条的苦难,才换来了我如今荒谬地舒适的生活。</p><p>尽管我很高兴至少稍微了解了一点这些人是谁,但现在我又开始为所有其他灰色的人感到难过:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/small-tree-missing-parts.png" target="_blank" rel="noreferrer"><img src="'+n+'" alt="small stick figure family tree from Me to My Great-Great-Grandparents showing that you know almost nothing about your great-great-grandparents"></a></strong></p><p>这一切让我开始思考家谱学 (genealogy),以及这个概念本身有多迷人。如果我不停地把家谱往上、往上、再往上延伸,会发生什么?第四代堂表亲 (fourth cousin) 究竟是什么意思,我有多少个,他们现在都在哪里?对于 2300 年的某个小孩来说,我是他家谱树高高在上的那一层里、和几百个人并列的、看起来老掉牙的家伙之一——这有多诡异?正常情况下,我会自己在网上无止境地搜索这些东西,但既然 Wait But Why 存在,那我们就一起来搞——</p><p><strong>过去:你的祖先锥</strong></p><p>那我们就从过去开始,看看如果一直沿着家谱树往上走会发生什么,我把它叫做你的祖先锥 (Ancestor Cone):</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/tree-128.png" target="_blank" rel="noreferrer"><img src="'+p+'" alt="Big Family Tree from you to your 128 great-great-great-great-great-grandparents"></a></strong></p><p>你可以看到,一旦开始往前追溯几代,事情很快就会变得一发不可收拾。最上面一排是那 128 人组成的、你的五世曾祖父母 (great⁵ grandparents),也就是你祖父母的祖父母的曾祖父母。让我觉得惊讶的是,你竟然在如此近的时间点上就有了如此庞大数量的祖先。按平均每代 25 到 30 年估算,这些人当中的大部分,在 1800 到 1825 年前后就跟你现在同岁。所以 19 世纪初的世界里,有 128 个彼此毫无关联的陌生人各自过着自己的日子,而他们每个人的基因都构成了今天的你的 1/128。</p><p>他们都是谁?他们住在哪些国家?他们各自的一生都做了些什么?他们熬过了哪些悲剧,又取得过哪些最了不起的成就?这张图里的 254 对亲子关系是什么样的?上面那 252 对姻亲关系里,哪些亲密而恩爱,哪些又愤怒又充满争斗?</p><p>对我来说最疯狂的事情是,这张只代表了你祖先过去 200 年的图,里面就包含了 127 段恋爱关系,每一段至少涉及一个关键的性爱瞬间,而其中大部分可能还涉及深深的爱情。你是 127 段浪漫故事的产物——仅仅是过去 200 年里。</p><p>好吧,我有点紧张,但我要试着再往回追溯得更远一点——</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/tree-many.png" target="_blank" rel="noreferrer"><img src="'+s+'" alt="Huge Family Tree from you to 12 generations back where there are 4,096 people"></a></p><p>好吧,这完全失控了。这张图只比上面那张往回多追溯了<em>五</em>代,看看这场面有多疯狂。</p><p>顶部那一层的 <em>4,096</em> 个人是你的曾曾曾曾曾曾曾曾曾曾曾祖父母(great10 grandparents)。他们中的大多数在 1600 年代下半叶时,正是你现在这个年纪,那时启蒙运动 (Enlightenment) 刚刚在欧洲开始。</p><p>你现在应该明白了,为什么有人告诉你他是几百年前某位著名皇室的后裔时,其实并没有那么了不起。看看你光是往回追 300 年就有多少祖先!在那顶部一层里,除了农民、学者、战士、画家、妓女、杀人犯、疯子和当时存在的任何其他类型的人之外,大概率也会有一些皇室成员。</p><p>最后,我知道我在<a href="https://waitbutwhy.com/2013/12/your-ancestor-is-jellyfish.html" target="_blank" rel="noreferrer">进化那篇文章</a>里已经讲过这一点了,但你仔细看看那顶部一层,你其实能看到里面有 4,096 个独立的小人——然后想想,如果你从那儿<em>随便</em>拿走一个,今天就不会有你。拜托。</p><p>你可能也注意到了,这些数字以指数方式飙升有些不太对劲——追溯三个世纪就已经到了 4,096,按这个速度继续下去,我们的祖先数量会变成这样:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/Pop-graph1.png" target="_blank" rel="noreferrer"><img src="'+i+'" alt="line representing the size of the highest living row of your family tree as you go back in time"></a></strong></p><p>这意味着到公元 1100 年左右,你会有 680 亿个祖先。问题在于,世界人口的走势是这样的:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/Pop-graph-w-pop1.png" target="_blank" rel="noreferrer"><img src="'+l+'" alt="blue line showing size of highest living family tree increasing as you go back in time crossing a red line representing the world population declining as you go back in time"></a></strong></p><p>那么这怎么解释呢?</p><p>用一个叫做<strong>谱系坍缩 (pedigree collapse)</strong> 的概念来解释,也就是当一个人最终的伴侣多少和自己有点血缘关系——甚至很近的血缘关系时会发生的情况。举个例子,如果两个表亲/堂亲生了个孩子,那这孩子就只有六个曾祖父母,而不是八个。或者换个说法,那孩子的家谱树上还是有八个曾祖父母的位置,但其中两个位置是另外两个位置的<em>重复</em>——</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/pedigree-collapse.png" target="_blank" rel="noreferrer"><img src="'+g+'" alt="pedigree collapse stick family tree showing that the child of first cousins only has three sets of great-grandparents"></a></strong></p><p>在你皱眉之前,先消化一下这个事实:根据罗格斯大学 (Rutgers) 人类学教授罗宾·福克斯 (Robin Fox) 的说法,<em>历史上 80% 的婚姻都是发生在二代表亲或更近的亲属之间</em>。<a href="#footnote2-1-952">1</a></p><p>原因是在人类历史的大部分时间里,人们一辈子都生活在方圆五英里之内,而这个范围里的其他人往往就是自己的直系和旁系亲属。想在求偶时避开自己的亲戚,男人得走出五英里以外——打了一天猎之后,你实在没那个心情。</p><p>在西方世界,这在很大程度上已经成为过去,但在世界许多地方,这仍然是普遍的做法——比如,在中东和北非的大部分地区,今天超过 50% 的婚姻发生在二代表亲或更近的亲属之间。<a href="#footnote2-2-952">2</a></p><p>所以上面那 4,096 个人的群体?其中有相当一部分位置无疑是重复的,这意味着不同个体的真实数量可能会略低一些——而对于几千年前的某个人来说,他们第 10 代祖先的数量会<em>远远</em>少于 4,096。</p><p>由于谱系坍缩,如果你把家谱树往回一直延伸、一直延伸,它反而会开始<em>变小</em>,最终形成一个菱形:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/diamond.png" target="_blank" rel="noreferrer"><img src="'+u+'" alt="zoomed out view of pedigree collapse showing a family tree expanding from today to 1200AD and contracting as you go farther back in time"></a></strong></p><p>对我们大多数人来说,祖先锥体最宽的位置大约出现在公元 1200 年,<a href="#footnote2-3-952">3</a> 那时我们的家谱树规模已经接近当时的世界总人口。从那一点开始,谱系坍缩就变成比常规的向上 x2 倍增更强的因素,家谱树开始向内收敛。</p><p><strong>现在:你现在还活着的亲戚</strong></p><p>那么在我们所有人都参与其中的这场生育狂潮里,我们和今天地球上其他人的关系又是怎么一回事呢?</p><p>最简单的思考方式是:世界上每一个陌生人都是你的表亲,唯一的问题是他们跟你有多远。表亲的级数(一代、二代等等)其实就是在说,你得往上追溯多少代才能找到共同的祖先。一代表亲(first cousin),你只需要往上追溯两代就能找到共同的祖父母。二代表亲(second cousin),你得往上追溯三代,找到共同的曾祖父母。五代表亲(fifth cousin),你得往上追溯六代,才能找到那对共同的高高祖父母。</p><p>因为很多人搞不清楚表亲的定义,我做了个小图表来说明什么是二代表亲。</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/3rd-cousins.png" target="_blank" rel="noreferrer"><img src="'+m+'" alt="visual diagram explaining second cousins"></a></strong></p><p>所以注意,对你和你的二代表亲来说,A) 你的父母是他们父母的一代表亲,B) 你们的祖父母是兄弟姐妹,C) <em>他们的</em>曾祖父母就是你们共同的曾祖父母。对三代表亲来说,一切都往上提一级——你的父母是<em>二代</em>表亲,你的祖父母是一代表亲,你的曾祖父母是兄弟姐妹,你们有一对共同的高祖父母。</p><p>(至于所谓的「once/twice removed」(隔一代/隔两代),说的是不在同一代的情况——你的二代表亲的孩子就是你的「二代表亲隔一代」(second cousin once removed),因为跟你差了一代;你祖父的一代表亲就是你的「一代表亲隔两代」(first cousin twice removed)。纯粹的二代、三代、四代表亲必须跟你在同一代。)</p><p>你拥有的表亲数量,随着代数距离的增加呈指数级增长。你可能只有少数几个一代表亲,但你很可能有几百个三代表亲、几千个五代表亲,以及超过一百万个八代表亲。</p><p>因为写这篇文章的时候我对这个概念有点着迷,我决定卷起书呆子的袖子,琢磨出了一个公式:</p><p><strong>(n-1) 2d nd</strong></p><p>——其中 <em>n</em> 是每个家庭平均有几个孩子,<em>d</em> 是你想算总数的表亲代数(公式的解释在文章末尾)。(P.S. 我现在超得意。)(但也有点慌,因为可能有更好的算法,欢迎在评论区提建议。)</p><p>所以如果你家庭平均每对夫妇生两个孩子 (n=2),想算你有多少三代表亲 (d=3),就是 (2-1) 23 * 23 = 64 个。</p><p>如果你家庭平均每对夫妇生三个孩子 (n=3),你会有多少四代表亲 (d=4) 呢?就是 (3-1) 24 * 34 = 2,592 个。</p><p>把这个公式用在你自己身上很难,因为你不知道 <em>n</em>,也就是你大家族里平均每人生几个孩子——但你可以用你所在国家的平均每家孩子数来大致估算一下。我在下面算了一些例子:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/Country-chart1.png" target="_blank" rel="noreferrer"><img src="'+h+'" alt="average number of cousins a person has by country, Singapore .24 first cousins and Niger 100 cousins"></a></p><p>最让我觉得有意思的是,这些数字增长得如此指数化,以至于取世界平均每家孩子数 (2.36)<a href="#footnote2-4-952">4</a>,你可以用公式算出:如果生育在各文化和国家之间均匀混合,那么你在地球上最远的亲戚也就是 15 代表亲。</p><p>然而,由于生育并不是均匀混合的,而是大多局限在各国和各文化内部,你所在的文化或族群里跟你最远的那个人,可能比 15 代表亲还要近一些,而你在地球上最远的亲戚关系可能远到 50 代表亲。<a href="#footnote2-5-952">5</a></p><p>不管怎样,你有几百甚至几千个三代和四代表亲,而且你可能在不知情的情况下就跟其中一些人是朋友——你甚至可能正在跟其中一个约会。</p><p>另一种看这件事的方式是自上而下,看看亲缘距离随着世代往下走会被多快地放大——你和你的兄弟姐妹从小在同一个家里长大,你们的孩子会是表亲,可能是朋友也可能不是,你们的孙辈可能几乎不认识彼此。等到你和你兄弟姐妹的曾孙那一辈,他们<em>很可能</em>一辈子都不会见面,而你们的玄孙可能是彼此最好的朋友,却永远不会意识到他们的高祖父母是兄弟姐妹。</p><p>一个很好的例子:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/prince-chart1.png" target="_blank" rel="noreferrer"><img src="'+c+'" alt="prince chart showing the king and how his son, grandson, and great-grandson are kings but the prince and his descendants are the first, second, and third cousins of the king"></a></p><p><strong>未来:你的后代锥</strong></p><p>也许你不会有孩子,或者你的孩子不会有孩子。但除去这些可能性,你很可能最终会成为一个后代锥 (Descendant Cone) 的伟大始祖或始母,而这个锥体最终会占据人类中相当大的一块。在扩张到成千上万人之前的头几百年里,它大概看起来是这样:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/descendant-cone.png" target="_blank" rel="noreferrer"><img src="'+f+'" alt="reverse family tree showing your blood related descendants."></a></strong></p><p>让我们凑近看看你几百个五世玄孙 (great-great-great-great-great-grandchild) 中的一个:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/telia1.png" target="_blank" rel="noreferrer"><img src="'+d+'" alt="close up of the bottom row of your descendant tree with one stick figure highlighted and named Telia"></a></strong></p><p>小 Telia,大约出生于 2300 年,对你来说和上面 1800 年代初的那些祖先一样,是个谜。她的生命归功于你,她的性格中某处也许还带着你的一两个特质——但你们的联系仅此而已。</p><p><strong>派对结束了</strong></p><p>到目前为止在这篇文章里,你一直有幸作为所有家族树的核心人物出现。你是数千段浪漫爱情完美对齐后,共同孕育出的<strong>那一个</strong>孩子。你是一个庞大大家庭的中心,周围环绕着一圈圈兄弟姐妹和堂表亲。而现在,你又是一大片后代圆锥的伟大始祖。</p><p>但你只要换个视角,突然之间——你就成了 17 世纪某个人一万个后代中的一个;<strong>你</strong>才是那个二代堂表亲、三代堂表亲、四代堂表亲(想到自己不过是别人某个随机的二代表亲,感觉真怪);而对 Telia 来说,你不是什么伟大的族长或族母——你只是她的祖先圆锥顶端一个极其随机的小小火柴人,而且还很模糊,因为 Tim 没搞清楚怎么从 Pixelmator 导出高清图片,尽管他试了一堆办法:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/01/telia-cone.png" target="_blank" rel="noreferrer"><img src="'+y+'" alt="Telia Ancestor Cone showing you in the far top row with hundreds of other people alive today"></a></strong></p><p>最上面那一行的人大多是今天还活着的,而你根本不知道跟你一起站在 Telia 顶行上的都是谁——咖啡店那个打工的哥们儿,说不定也是她的太太太太太外祖父,你们俩不过是她成百上千个无名的、被遗忘的远古祖先中的两个而已。</p><p><strong>结论</strong></p><ul><li><p>现在我觉得自己既特别又重要,同时又觉得自己无关紧要、毫无意义。</p></li><li><p>写这篇文章真的让我深刻意识到一点:人类基本上就是自己基因的一个临时容器。150 年后,现在活着的 71 亿人都将死去,但我们所有的基因会活得好好的,继续住在别人身体里。</p></li><li><p>看完第一条结论,我还在为该觉得好还是觉得糟而摇摆不定。然后第二条把我自己给整抑郁了。不过为了给我垂头丧气的自尊心扔根骨头,我想考虑一个有趣的想法:我的后代或许根本不需要去问奶奶问题,才能了解我的生活、认识我这个人——技术改变一切。100 年后,我的曾曾孙可能可以轻松调出各种信息/照片/视频,想学什么就学什么,我敢肯定他啥也不会去查,因为他最不会去想的一件事,就是他曾曾祖父长啥样。妈的。</p></li><li><p>不管怎样,眼下想要了解你从哪里来,真的只有一个好办法——所以,开始问吧。</p></li></ul><hr><p>如果你喜欢 Wait But Why,可以订阅我们的 <strong><a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a></strong>,新文章发布时我们会发给你。</p><h2 id="想支持-wait-but-why-请访问我们的-patreon-页面。" tabindex="-1">想支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。 <a class="header-anchor" href="#想支持-wait-but-why-请访问我们的-patreon-页面。" aria-label="Permalink to &quot;想支持 Wait But Why,请访问我们的 **[Patreon 页面](https://patreon.com/waitbutwhy)**。&quot;">​</a></h2><p><strong>其他让你重新审视人生的 WBW 文章:</strong></p><p><a href="https://waitbutwhy.com/2013/12/your-ancestor-is-jellyfish.html" target="_blank" rel="noreferrer">认识你的祖先(全部)</a></p><p><a href="https://waitbutwhy.com/2014/05/life-weeks.html" target="_blank" rel="noreferrer">你以周为单位的人生</a></p><p><a href="https://waitbutwhy.com/2014/12/what-makes-you-you.html" target="_blank" rel="noreferrer">是什么让你成为你?</a></p><p><strong>表亲计算公式说明</strong></p><p>公式是 <strong>(n-1) 2d nd</strong></p><p>——其中 <em>n</em> 是一个家庭平均生育的孩子数,<em>d</em> 是你想计算的表亲/堂亲的级数。</p><p>它归结为一个简单的乘法:顶层兄弟姐妹的数量 [(n-1) 2d] 乘以每个顶层兄弟姐妹最终在你这一代产生的&quot;最终后代数量&quot; (nd)。</p><p>示例 1</p><p>对于一代表亲/堂亲来说,&quot;顶层&quot;是父母那一代,因为那是我们在家谱中往&quot;下&quot;走到一代表亲之前先横着走&quot;侧向&quot;的那一代。在这个例子里,&quot;顶层兄弟姐妹&quot;的数量就是你有血缘关系的姑姨叔舅的数量,也就是你父母兄弟姐妹的合计数量。我们算这个数字的方法是:一个普通家庭孩子总数减一(减一去掉的是那个当父/母的人,剩下的就是兄弟姐妹数)乘以我们需要算兄弟姐妹的顶层祖先数量(这里是 2,因为有两个父母)。所以计算一代表亲时,如果平均一个家庭有三个孩子(n = 3),顶层兄弟姐妹的数量就是 (3 – 1) * 21,即 2 个兄弟姐妹乘以 2 个父母,等于 4 个顶层兄弟姐妹。</p><p>第二步是算出每个顶层兄弟姐妹最终会产生多少个一代表亲。由于我们把一个家庭、文化或国家的平均孩子数作为常数 <em>n</em>,只要把每个顶层兄弟姐妹乘以 <em>n</em> 就能得到他们的孩子数。因为他们的孩子也会有同样数量 <em>n</em> 个孩子,所以往下走两代就要把顶层兄弟姐妹乘以 n2——可以简化为 nd。对于一代表亲,我们只需要乘一次 <em>n</em>,因为只往下走一代。</p><p>所以在一个总是有三个孩子的家庭里,d=1,n=3,(n-1) 2d nd 算出来就是 4 x 3 = 12。这是对的,因为你父母合起来有 4 个兄弟姐妹,每人有 3 个孩子。</p><p>示例 2</p><p>要算出如果每个人都生两个孩子的话,一个人有多少个三代表亲 (third cousin),我们令 n=2,d=3。这里,顶层的兄弟姐妹在曾祖父母那一辈,因为是<em>他们的</em>兄弟姐妹的曾孙才是你的三代表亲——正是在曾祖父母这一辈,我们先横向移动,然后往下走,才能找到我们的三代表亲。</p><p>所以这里曾祖父母那一辈兄弟姐妹的数量是 (n-1) 2d = (2-1) 23 = 8。这个结果说得通,因为你有八个曾祖父母,每个人各有一个兄弟姐妹(因为在这个例子里每个人生两个孩子,也就是每人有一个兄弟姐妹)。每个曾祖父母有 nd = 23 = 8 个曾孙(因为我们往下走了四代,每一代生两个孩子),所以这个例子里三代表亲的总数是 8 x 8 = 64。</p><p><strong>______</strong></p><p><strong>参考资料</strong></p><p><a href="http://discovermagazine.com/2003/aug/featkiss#.UuiJgWQo46g" target="_blank" rel="noreferrer">Richard Conniff. “Go Ahead, Kiss Your Cousin.”</a></p><p><a href="http://www.straightdope.com/columns/read/412/2-4-8-16-how-can-you-always-have-more-ancestors-as-you-go-back-in-time" target="_blank" rel="noreferrer">The Straight Dope: 2, 4, 8, 16, … how can you always have MORE ancestors as you go back in time?</a></p><p><a href="http://www.nationmaster.com/graph/peo_tot_fer_rat-people-total-fertility-rate" target="_blank" rel="noreferrer">NationMaster 各国生育率</a></p><p>John E. Pattison (2007), Estimating Inbreeding in Large Semi-isolated Populations: Effects of Varying Generation Length and of Migration, <em>American Journal of Human Biology</em> <strong>19</strong>(4):495-510</p><p><a href="https://en.wikipedia.org/wiki/Richard_Dawkins" title="Richard Dawkins" target="_blank" rel="noreferrer">道金斯 (Richard Dawkins)</a> (1995) 《<a href="https://en.wikipedia.org/wiki/River_Out_of_Eden" title="River Out of Eden" target="_blank" rel="noreferrer">伊甸园之河</a>》中的 <em>All Africa and her progenies</em> 一章。</p><hr><ol><li><p><a href="http://discovermagazine.com/2003/aug/featkiss#.UuiJgWQo46g" target="_blank" rel="noreferrer">Richard Conniff. “Go Ahead, Kiss Your Cousin.”</a><a href="#note2-1-952">↩</a></p></li><li><p><a href="http://discovermagazine.com/2003/aug/featkiss#.UuiJgWQo46g" target="_blank" rel="noreferrer">Richard Conniff. “Go Ahead, Kiss Your Cousin.”</a><a href="#note2-2-952">↩</a></p></li><li><p><a href="http://www.straightdope.com/columns/read/412/2-4-8-16-how-can-you-always-have-more-ancestors-as-you-go-back-in-time" target="_blank" rel="noreferrer">The Straight Dope: 2, 4, 8, 16, … how can you always have MORE ancestors as you go back in time?</a><a href="#note2-3-952">↩</a></p></li><li><p><a href="http://www.nationmaster.com/graph/peo_tot_fer_rat-people-total-fertility-rate" target="_blank" rel="noreferrer">http://www.nationmaster.com/graph/peo_tot_fer_rat-people-total-fertility-rate</a><a href="#note2-4-952">↩</a></p></li><li><p><a href="http://www.straightdope.com/columns/read/412/2-4-8-16-how-can-you-always-have-more-ancestors-as-you-go-back-in-time" target="_blank" rel="noreferrer">The Straight Dope: 2, 4, 8, 16, … how can you always have MORE ancestors as you go back in time?</a><a href="#note2-5-952">↩</a></p></li></ol><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2014/01/your-family-past-present-and-future.html&amp;description=Your%20Family:%20Past,%20Present,%20and%20Future" target="_blank" rel="noreferrer"><img src="'+w+'" alt=""></a></p>',106)])])}const A=t(_,[["render",b]]);export{F as __pageData,A as default};
